(()=>{"use strict";const getStoredTheme=()=>localStorage.getItem("theme");const setStoredTheme=(theme)=>localStorage.setItem("theme",theme);const getPreferredTheme=()=>{const storedTheme=getStoredTheme();if(storedTheme){return storedTheme}
return window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light"};const setTheme=(theme)=>{if(theme==="auto"){document.documentElement.setAttribute("data-bs-theme",window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light")}else{document.documentElement.setAttribute("data-bs-theme",theme)}};const showActiveTheme=(theme,focus=!1)=>{const themeToggle=document.getElementById("theme-toggle");if(!themeToggle){return}
const icon=themeToggle.querySelector("i");icon.className=theme==="dark"?"bi bi-sun":"bi bi-moon";if(focus){themeToggle.focus()}};window.addEventListener("DOMContentLoaded",()=>{const storedTheme=getStoredTheme();const preferredTheme=getPreferredTheme();setTheme(storedTheme||preferredTheme);showActiveTheme(storedTheme||preferredTheme);const themeToggle=document.getElementById("theme-toggle");if(themeToggle){themeToggle.addEventListener("click",(e)=>{e.preventDefault();const currentTheme=getStoredTheme()||preferredTheme;const newTheme=currentTheme==="dark"?"light":"dark";setStoredTheme(newTheme);setTheme(newTheme);showActiveTheme(newTheme,!0)})}
window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",()=>{const currentTheme=getStoredTheme()||preferredTheme;if(currentTheme!=="light"&&currentTheme!=="dark"){setTheme(preferredTheme);showActiveTheme(preferredTheme)}})})})()